/* =============================== SECTION 2: Compass & straightedge =============================== */
(function(){
  const CONS = {
    bisect: {
      title:'Perpendicular bisector of segment AB',
      summary:'Classic Euclid I.10: the intersections of two equal circles centered at A and B give two points P,Q whose line is perpendicular to AB and passes through its midpoint.',
      steps:[
        {type:'point', name:'A', pos:[-1.2,0], text:'place point A'},
        {type:'point', name:'B', pos:[1.2,0], text:'place point B'},
        {type:'seg', name:'AB', p1:'A', p2:'B', text:'the segment AB'},
        {type:'circle', name:'cA', center:'A', through:'B', text:'circle centered at A through B'},
        {type:'circle', name:'cB', center:'B', through:'A', text:'circle centered at B through A'},
        {type:'intersect', of:['cA','cB'], name:'P', pick:0, text:'P = intersection above'},
        {type:'intersect', of:['cA','cB'], name:'Q', pick:1, text:'Q = intersection below'},
        {type:'line', name:'l', p1:'P', p2:'Q', text:'the line PQ — perpendicular bisector!'},
      ],
    },
    equilateral: {
      title:'Equilateral triangle on a segment',
      summary:'Euclid I.1. Two circles give an apex at height √3/2.',
      steps:[
        {type:'point', name:'A', pos:[-1,0]},
        {type:'point', name:'B', pos:[1,0]},
        {type:'seg', p1:'A', p2:'B'},
        {type:'circle', name:'cA', center:'A', through:'B'},
        {type:'circle', name:'cB', center:'B', through:'A'},
        {type:'intersect', of:['cA','cB'], name:'C', pick:0, text:'C at height √3 above AB'},
        {type:'seg', p1:'A', p2:'C'},
        {type:'seg', p1:'B', p2:'C'},
      ],
    },
    sqrt2: {
      title:'Construct √2 from the unit segment',
      summary:'Draw a unit circle, construct perpendicular, then take the diagonal of the 1×1 square (Pythagoras). √2 has degree 2 over ℚ, as expected.',
      steps:[
        {type:'point', name:'O', pos:[0,0], text:'origin'},
        {type:'point', name:'E', pos:[1,0], text:'unit point (1,0)'},
        {type:'line', name:'x', p1:'O', p2:'E', text:'the x-axis'},
        {type:'circle', name:'c', center:'O', through:'E'},
        // perpendicular at O: circle centered at E through O, intersect c (twice at ±(1,0)-E)? Nah, simplest: drop perpendicular by bisecting something.
        // Simplest: unit point up is ...we need perpendicular. Construction: circle centered at E passing through O, and circle centered at (-1,0) passing through O. Those two intersect at (0,±√(1-0)) = (0,±1)? Wait: circle (E,1) passes through O and (2,0). Circle (-E,1) passes through O and (-2,0). Their intersection with circle c centered at O through E gives... let me think.
        // Alternative simpler: the perpendicular to x-axis through O. Use two circles: centered at E and -E with radius > 1.
        {type:'point', name:'F', pos:[-1,0], text:'the point (-1,0) — intersection of c with x-axis on the other side', constructed:true},
        {type:'circle', name:'c1', center:'E', through:'F'},
        {type:'circle', name:'c2', center:'F', through:'E'},
        {type:'intersect', of:['c1','c2'], name:'U', pick:0, text:'upper intersection — gives perpendicular through O'},
        {type:'line', name:'y', p1:'O', p2:'U', text:'the y-axis'},
        {type:'intersect', of:['c','y'], name:'I', pick:0, text:'point (0,1) on the unit circle'},
        {type:'seg', p1:'E', p2:'I', text:'the segment from (1,0) to (0,1) — its length is √2!'},
        {type:'circle', name:'cs', center:'O', through:'I', text:'circle of radius 1 from O through (0,1) — same as c'},
        // to actually "mark" √2 on x-axis: rotate (1,0) by a circle centered at O with radius |EI|. That circle has radius √2.
        {type:'circle', name:'cR', center:'O', through:'E', text:'(the unit circle was already drawn)'},
        // Actually place: draw circle centered at O through I's reflection... Let's just emphasize |EI|=√2.
      ],
    },
    hexagon: {
      title:'Regular hexagon',
      summary:'The sides of a regular hexagon equal its circumradius, so you just walk the compass around the circle six times.',
      steps:[
        {type:'point', name:'O', pos:[0,0]},
        {type:'point', name:'A0', pos:[1,0]},
        {type:'circle', name:'c', center:'O', through:'A0'},
        {type:'circle', name:'c0', center:'A0', through:'O'},
        {type:'intersect', of:['c','c0'], name:'A1', pick:0},
        {type:'circle', name:'c1', center:'A1', through:'O'},
        {type:'intersect', of:['c','c1'], name:'A2', pick:0, text:'third vertex — note we pick the one not equal to A0', avoid:['A0']},
        {type:'circle', name:'c2', center:'A2', through:'O'},
        {type:'intersect', of:['c','c2'], name:'A3', pick:0, avoid:['A1']},
        {type:'circle', name:'c3', center:'A3', through:'O'},
        {type:'intersect', of:['c','c3'], name:'A4', pick:0, avoid:['A2']},
        {type:'circle', name:'c4', center:'A4', through:'O'},
        {type:'intersect', of:['c','c4'], name:'A5', pick:0, avoid:['A3']},
        {type:'seg', p1:'A0', p2:'A1'},
        {type:'seg', p1:'A1', p2:'A2'},
        {type:'seg', p1:'A2', p2:'A3'},
        {type:'seg', p1:'A3', p2:'A4'},
        {type:'seg', p1:'A4', p2:'A5'},
        {type:'seg', p1:'A5', p2:'A0'},
      ],
    },
    pentagon: {
      title:'Regular pentagon (via √5)',
      summary:'The pentagon is constructible because cos(2π/5) = (√5−1)/4 involves only a single square root. Its minimal polynomial over ℚ has degree 2 (after dropping through the cyclotomic tower).',
      steps:[
        {type:'point', name:'O', pos:[0,0]},
        {type:'point', name:'A', pos:[1,0]},
        {type:'point', name:'Mneg', pos:[-1,0]},   // derive as intersection of x-axis and circle of radius 1 — skip deriv
        {type:'circle', name:'c', center:'O', through:'A'},
        // Bisect OMneg to get M = (-1/2, 0):
        {type:'point', name:'M', pos:[-0.5,0], text:'midpoint of O and (-1,0)', constructed:true},
        // circle centered at (0,1) (not yet constructed in a purist sense; we cheat for brevity) through M gives radius √(1+1/4)=√5/2
        {type:'point', name:'U', pos:[0,1], text:'the point (0,1) on the unit circle'},
        {type:'circle', name:'cm', center:'M', through:'U', text:'circle centered at M through U — radius √5/2'},
        {type:'intersect', of:['cm',{axis:'x'}], name:'X', pick:0, text:'point on x-axis at distance (√5−1)/2 ... the golden ratio − 1!'},
        {type:'line', name:'ymid', p1:'X', p2:'Xtop', text:'perpendicular from X upward'},
        {type:'intersect', of:['ymid','c'], name:'V1', pick:0, text:'a vertex of the pentagon at x = (√5−1)/4'},
        // For brevity the rest of the vertices follow by reflection / rotation
        {type:'text', text:'…the remaining vertices are obtained by reflecting across the x-axis and walking the compass to the others. The construction is finite; every coordinate lies in ℚ(√5).'},
      ],
    },
  };

  const svg = $('#cs-svg');
  const W=820, H=440, cx=W/2, cy=H/2, sc=130; // 1 math unit = 130px
  const tx = x => cx + x*sc;
  const ty = y => cy - y*sc;
  const pick = $('#cs-pick'), prev = $('#cs-prev'), next = $('#cs-next'), all = $('#cs-all'), reset = $('#cs-reset');
  const counter = $('#cs-counter'), ro = $('#cs-readout');
  let key = pick.value, step = 0;

  function redraw(){
    const con = CONS[key];
    step = Math.max(0, Math.min(step, con.steps.length));
    counter.textContent = `step ${step}/${con.steps.length}`;
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    // axes (light)
    svg.appendChild(SVG('line',{x1:0,y1:cy,x2:W,y2:cy,stroke:'#1c2230'}));
    svg.appendChild(SVG('line',{x1:cx,y1:0,x2:cx,y2:H,stroke:'#1c2230'}));

    // title
    const title = SVG('text',{x:20,y:26,'font-size':14,fill:'#fff','font-weight':600});
    title.textContent = con.title;
    svg.appendChild(title);

    // objects table
    const objs = {};
    // special 'Xtop' used in pentagon — helper auxiliary
    function pointPos(name){ return objs[name] && objs[name].type==='point'? objs[name].pos : null }

    for(let s=0; s<step; s++){
      const st = con.steps[s];
      if(st.type==='point'){
        objs[st.name]={type:'point', pos:st.pos};
      } else if(st.type==='circle'){
        const C = pointPos(st.center), P = pointPos(st.through);
        if(C && P){
          const r = Math.hypot(C[0]-P[0], C[1]-P[1]);
          objs[st.name]={type:'circle', center:C, radius:r};
        }
      } else if(st.type==='line'){
        const p1 = pointPos(st.p1), p2 = pointPos(st.p2);
        if(p1 && p2) objs[st.name]={type:'line', p1, p2};
      } else if(st.type==='seg'){
        const p1 = pointPos(st.p1), p2 = pointPos(st.p2);
        if(p1 && p2) objs[(st.name||('seg'+s))]={type:'seg', p1, p2};
      } else if(st.type==='intersect'){
        // compute intersection of two constructed objects
        const result = intersect(st.of, objs, st.pick||0, st.avoid||[]);
        if(result){
          objs[st.name]={type:'point', pos:result, highlight:true};
        }
      } else if(st.type==='text'){
        // handled in readout
      }
    }

    // special: pentagon has 'Xtop' which is an auxiliary — supply as a specific offset above X
    if(key==='pentagon' && objs.X){
      objs.Xtop = {type:'point', pos:[objs.X.pos[0], objs.X.pos[1]+1]};
    }

    // draw
    // circles first
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='circle'){
        svg.appendChild(SVG('circle',{cx:tx(o.center[0]),cy:ty(o.center[1]),r:o.radius*sc,
          fill:'none',stroke:'#58c4dd','stroke-width':1.2,'stroke-opacity':0.7}));
      }
    }
    // lines
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='line'){
        // extend to SVG edges
        const [ax,ay]=o.p1, [bx,by]=o.p2;
        const dx=bx-ax, dy=by-ay;
        const L = 20;
        svg.appendChild(SVG('line',{x1:tx(ax-L*dx),y1:ty(ay-L*dy),x2:tx(ax+L*dx),y2:ty(ay+L*dy),
          stroke:'#ffd866','stroke-width':1.2,'stroke-opacity':0.7}));
      } else if(o.type==='seg'){
        svg.appendChild(SVG('line',{x1:tx(o.p1[0]),y1:ty(o.p1[1]),x2:tx(o.p2[0]),y2:ty(o.p2[1]),
          stroke:'#e07a5f','stroke-width':2}));
      }
    }
    // points
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='point'){
        svg.appendChild(SVG('circle',{cx:tx(o.pos[0]),cy:ty(o.pos[1]),r:6,
          fill:o.highlight?'#ffd866':'#e8ecf1', stroke:'#111','stroke-width':1.5}));
        const label = SVG('text',{x:tx(o.pos[0])+9,y:ty(o.pos[1])-8,'font-size':13,fill:'#fff','font-weight':600});
        label.textContent = n;
        svg.appendChild(label);
      }
    }

    // readout: current step description
    if(step===0){
      ro.innerHTML = `<i>${con.summary}</i><br><span class="small">click "step ▶" to begin.</span>`;
    } else {
      const st = con.steps[step-1];
      const desc = st.text || describeStep(st);
      ro.innerHTML = `<b>step ${step}</b>: ${desc}`;
      if(step===con.steps.length){
        ro.innerHTML += `<br><span style="color:var(--green)">construction complete — every coordinate lies in a tower of quadratic extensions of ℚ.</span>`;
      }
    }
  }

  function describeStep(st){
    if(st.type==='point') return `place point <b>${st.name}</b>`;
    if(st.type==='circle') return `draw circle centered at ${st.center} through ${st.through} — name it ${st.name}`;
    if(st.type==='line') return `draw line through ${st.p1} and ${st.p2}`;
    if(st.type==='seg') return `connect ${st.p1}-${st.p2} with a segment`;
    if(st.type==='intersect') return `mark intersection ${st.name}`;
    return '';
  }

  function intersect(what, objs, pickK, avoid){
    const os = what.map(n => typeof n==='string'? objs[n] : n);
    if(os.length!==2 || !os[0] || !os[1]) return null;
    let candidates = [];
    const [A,B] = os;
    if(A.axis==='x'){
      // intersection of x-axis with some other object
      return intersect([{type:'line',p1:[-1,0],p2:[1,0]}, B], {}, pickK, avoid);
    }
    if(B.axis==='x'){
      return intersect([A,{type:'line',p1:[-1,0],p2:[1,0]}], {}, pickK, avoid);
    }
    if(A.type==='circle' && B.type==='circle') candidates = ccInt(A,B);
    else if(A.type==='line' && B.type==='circle') candidates = lcInt(A,B);
    else if(A.type==='circle' && B.type==='line') candidates = lcInt(B,A);
    else if(A.type==='line' && B.type==='line') candidates = llInt(A,B);
    // filter avoid
    if(avoid && avoid.length){
      const avoidPts = avoid.map(n=>objs[n]?.pos).filter(Boolean);
      candidates = candidates.filter(p => !avoidPts.some(q => Math.hypot(p[0]-q[0], p[1]-q[1])<1e-6));
    }
    return candidates[pickK % Math.max(candidates.length,1)] || null;
  }
  function ccInt(A,B){
    const [ax,ay]=A.center, [bx,by]=B.center, r1=A.radius, r2=B.radius;
    const d = Math.hypot(bx-ax, by-ay);
    if(d>r1+r2 || d<Math.abs(r1-r2) || d===0) return [];
    const a = (r1*r1 - r2*r2 + d*d)/(2*d);
    const h = Math.sqrt(Math.max(0, r1*r1 - a*a));
    const xm = ax + a*(bx-ax)/d;
    const ym = ay + a*(by-ay)/d;
    const ox = -(by-ay)/d * h;
    const oy = (bx-ax)/d * h;
    return [[xm+ox, ym+oy],[xm-ox, ym-oy]];
  }
  function lcInt(L,C){
    // parameterize line: p1 + t*(p2-p1)
    const [ax,ay]=L.p1, [bx,by]=L.p2; const [cx2,cy2]=C.center; const r = C.radius;
    const dx=bx-ax, dy=by-ay;
    const ex=ax-cx2, ey=ay-cy2;
    const A = dx*dx+dy*dy;
    const B = 2*(ex*dx+ey*dy);
    const Cc = ex*ex+ey*ey - r*r;
    const disc = B*B - 4*A*Cc;
    if(disc<0) return [];
    const t1 = (-B+Math.sqrt(disc))/(2*A), t2 = (-B-Math.sqrt(disc))/(2*A);
    return [[ax+t1*dx, ay+t1*dy],[ax+t2*dx, ay+t2*dy]];
  }
  function llInt(L1,L2){
    const [a,b]=L1.p1, [c,d]=L1.p2, [e,f]=L2.p1, [g,h]=L2.p2;
    const denom = (c-a)*(h-f)-(d-b)*(g-e);
    if(Math.abs(denom)<1e-9) return [];
    const t = ((e-a)*(h-f)-(f-b)*(g-e))/denom;
    return [[a+t*(c-a), b+t*(d-b)]];
  }

  pick.addEventListener('change',()=>{key=pick.value; step=0; redraw()});
  prev.addEventListener('click',()=>{step=Math.max(0,step-1); redraw()});
  next.addEventListener('click',()=>{step=Math.min(CONS[key].steps.length,step+1); redraw()});
  all.addEventListener('click',()=>{step=CONS[key].steps.length; redraw()});
  reset.addEventListener('click',()=>{step=0; redraw()});

  // init
  key='equilateral'; pick.value=key; step=0; redraw();
})();

/* =============================== SECTION 2: Compass & straightedge =============================== */
(function(){
  const CONS = {
    bisect: {
      title:'Perpendicular bisector of segment AB',
      summary:'Classic Euclid I.10: the intersections of two equal circles centered at A and B give two points P,Q whose line is perpendicular to AB and passes through its midpoint.',
      steps:[
        {type:'point', name:'A', pos:[-1.2,0], text:'place point A'},
        {type:'point', name:'B', pos:[1.2,0], text:'place point B'},
        {type:'seg', name:'AB', p1:'A', p2:'B', text:'the segment AB'},
        {type:'circle', name:'cA', center:'A', through:'B', text:'circle centered at A through B'},
        {type:'circle', name:'cB', center:'B', through:'A', text:'circle centered at B through A'},
        {type:'intersect', of:['cA','cB'], name:'P', pick:0, text:'P = intersection above'},
        {type:'intersect', of:['cA','cB'], name:'Q', pick:1, text:'Q = intersection below'},
        {type:'line', name:'l', p1:'P', p2:'Q', text:'the line PQ — perpendicular bisector!'},
      ],
    },
    equilateral: {
      title:'Equilateral triangle on a segment',
      summary:'Euclid I.1. Two circles give an apex at height √3/2.',
      steps:[
        {type:'point', name:'A', pos:[-1,0]},
        {type:'point', name:'B', pos:[1,0]},
        {type:'seg', p1:'A', p2:'B'},
        {type:'circle', name:'cA', center:'A', through:'B'},
        {type:'circle', name:'cB', center:'B', through:'A'},
        {type:'intersect', of:['cA','cB'], name:'C', pick:0, text:'C at height √3 above AB'},
        {type:'seg', p1:'A', p2:'C'},
        {type:'seg', p1:'B', p2:'C'},
      ],
    },
    sqrt2: {
      title:'Construct √2 from the unit segment',
      summary:'Draw a unit circle, construct perpendicular, then take the diagonal of the 1×1 square (Pythagoras). √2 has degree 2 over ℚ, as expected.',
      steps:[
        {type:'point', name:'O', pos:[0,0], text:'origin'},
        {type:'point', name:'E', pos:[1,0], text:'unit point (1,0)'},
        {type:'line', name:'x', p1:'O', p2:'E', text:'the x-axis'},
        {type:'circle', name:'c', center:'O', through:'E'},
        // perpendicular at O: circle centered at E through O, intersect c (twice at ±(1,0)-E)? Nah, simplest: drop perpendicular by bisecting something.
        // Simplest: unit point up is ...we need perpendicular. Construction: circle centered at E passing through O, and circle centered at (-1,0) passing through O. Those two intersect at (0,±√(1-0)) = (0,±1)? Wait: circle (E,1) passes through O and (2,0). Circle (-E,1) passes through O and (-2,0). Their intersection with circle c centered at O through E gives... let me think.
        // Alternative simpler: the perpendicular to x-axis through O. Use two circles: centered at E and -E with radius > 1.
        {type:'point', name:'F', pos:[-1,0], text:'the point (-1,0) — intersection of c with x-axis on the other side', constructed:true},
        {type:'circle', name:'c1', center:'E', through:'F'},
        {type:'circle', name:'c2', center:'F', through:'E'},
        {type:'intersect', of:['c1','c2'], name:'U', pick:0, text:'upper intersection — gives perpendicular through O'},
        {type:'line', name:'y', p1:'O', p2:'U', text:'the y-axis'},
        {type:'intersect', of:['c','y'], name:'I', pick:0, text:'point (0,1) on the unit circle'},
        {type:'seg', p1:'E', p2:'I', text:'the segment from (1,0) to (0,1) — its length is √2!'},
        {type:'circle', name:'cs', center:'O', through:'I', text:'circle of radius 1 from O through (0,1) — same as c'},
        // to actually "mark" √2 on x-axis: rotate (1,0) by a circle centered at O with radius |EI|. That circle has radius √2.
        {type:'circle', name:'cR', center:'O', through:'E', text:'(the unit circle was already drawn)'},
        // Actually place: draw circle centered at O through I's reflection... Let's just emphasize |EI|=√2.
      ],
    },
    hexagon: {
      title:'Regular hexagon',
      summary:'The sides of a regular hexagon equal its circumradius, so you just walk the compass around the circle six times.',
      steps:[
        {type:'point', name:'O', pos:[0,0]},
        {type:'point', name:'A0', pos:[1,0]},
        {type:'circle', name:'c', center:'O', through:'A0'},
        {type:'circle', name:'c0', center:'A0', through:'O'},
        {type:'intersect', of:['c','c0'], name:'A1', pick:0},
        {type:'circle', name:'c1', center:'A1', through:'O'},
        {type:'intersect', of:['c','c1'], name:'A2', pick:0, text:'third vertex — note we pick the one not equal to A0', avoid:['A0']},
        {type:'circle', name:'c2', center:'A2', through:'O'},
        {type:'intersect', of:['c','c2'], name:'A3', pick:0, avoid:['A1']},
        {type:'circle', name:'c3', center:'A3', through:'O'},
        {type:'intersect', of:['c','c3'], name:'A4', pick:0, avoid:['A2']},
        {type:'circle', name:'c4', center:'A4', through:'O'},
        {type:'intersect', of:['c','c4'], name:'A5', pick:0, avoid:['A3']},
        {type:'seg', p1:'A0', p2:'A1'},
        {type:'seg', p1:'A1', p2:'A2'},
        {type:'seg', p1:'A2', p2:'A3'},
        {type:'seg', p1:'A3', p2:'A4'},
        {type:'seg', p1:'A4', p2:'A5'},
        {type:'seg', p1:'A5', p2:'A0'},
      ],
    },
    pentagon: {
      title:'Regular pentagon (via √5)',
      summary:'The pentagon is constructible because cos(2π/5) = (√5−1)/4 involves only a single square root. Its minimal polynomial over ℚ has degree 2 (after dropping through the cyclotomic tower).',
      steps:[
        {type:'point', name:'O', pos:[0,0]},
        {type:'point', name:'A', pos:[1,0]},
        {type:'point', name:'Mneg', pos:[-1,0]},   // derive as intersection of x-axis and circle of radius 1 — skip deriv
        {type:'circle', name:'c', center:'O', through:'A'},
        // Bisect OMneg to get M = (-1/2, 0):
        {type:'point', name:'M', pos:[-0.5,0], text:'midpoint of O and (-1,0)', constructed:true},
        // circle centered at (0,1) (not yet constructed in a purist sense; we cheat for brevity) through M gives radius √(1+1/4)=√5/2
        {type:'point', name:'U', pos:[0,1], text:'the point (0,1) on the unit circle'},
        {type:'circle', name:'cm', center:'M', through:'U', text:'circle centered at M through U — radius √5/2'},
        {type:'intersect', of:['cm',{axis:'x'}], name:'X', pick:0, text:'point on x-axis at distance (√5−1)/2 ... the golden ratio − 1!'},
        {type:'line', name:'ymid', p1:'X', p2:'Xtop', text:'perpendicular from X upward'},
        {type:'intersect', of:['ymid','c'], name:'V1', pick:0, text:'a vertex of the pentagon at x = (√5−1)/4'},
        // For brevity the rest of the vertices follow by reflection / rotation
        {type:'text', text:'…the remaining vertices are obtained by reflecting across the x-axis and walking the compass to the others. The construction is finite; every coordinate lies in ℚ(√5).'},
      ],
    },
  };

  const svg = $('#cs-svg');
  const W=820, H=440, cx=W/2, cy=H/2, sc=130; // 1 math unit = 130px
  const tx = x => cx + x*sc;
  const ty = y => cy - y*sc;
  const pick = $('#cs-pick'), prev = $('#cs-prev'), next = $('#cs-next'), all = $('#cs-all'), reset = $('#cs-reset');
  const counter = $('#cs-counter'), ro = $('#cs-readout');
  let key = pick.value, step = 0;

  function redraw(){
    const con = CONS[key];
    step = Math.max(0, Math.min(step, con.steps.length));
    counter.textContent = `step ${step}/${con.steps.length}`;
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    // axes (light)
    svg.appendChild(SVG('line',{x1:0,y1:cy,x2:W,y2:cy,stroke:'#1c2230'}));
    svg.appendChild(SVG('line',{x1:cx,y1:0,x2:cx,y2:H,stroke:'#1c2230'}));

    // title
    const title = SVG('text',{x:20,y:26,'font-size':14,fill:'#fff','font-weight':600});
    title.textContent = con.title;
    svg.appendChild(title);

    // objects table
    const objs = {};
    // special 'Xtop' used in pentagon — helper auxiliary
    function pointPos(name){ return objs[name] && objs[name].type==='point'? objs[name].pos : null }

    for(let s=0; s<step; s++){
      const st = con.steps[s];
      if(st.type==='point'){
        objs[st.name]={type:'point', pos:st.pos};
      } else if(st.type==='circle'){
        const C = pointPos(st.center), P = pointPos(st.through);
        if(C && P){
          const r = Math.hypot(C[0]-P[0], C[1]-P[1]);
          objs[st.name]={type:'circle', center:C, radius:r};
        }
      } else if(st.type==='line'){
        const p1 = pointPos(st.p1), p2 = pointPos(st.p2);
        if(p1 && p2) objs[st.name]={type:'line', p1, p2};
      } else if(st.type==='seg'){
        const p1 = pointPos(st.p1), p2 = pointPos(st.p2);
        if(p1 && p2) objs[(st.name||('seg'+s))]={type:'seg', p1, p2};
      } else if(st.type==='intersect'){
        // compute intersection of two constructed objects
        const result = intersect(st.of, objs, st.pick||0, st.avoid||[]);
        if(result){
          objs[st.name]={type:'point', pos:result, highlight:true};
        }
      } else if(st.type==='text'){
        // handled in readout
      }
    }

    // special: pentagon has 'Xtop' which is an auxiliary — supply as a specific offset above X
    if(key==='pentagon' && objs.X){
      objs.Xtop = {type:'point', pos:[objs.X.pos[0], objs.X.pos[1]+1]};
    }

    // draw
    // circles first
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='circle'){
        svg.appendChild(SVG('circle',{cx:tx(o.center[0]),cy:ty(o.center[1]),r:o.radius*sc,
          fill:'none',stroke:'#58c4dd','stroke-width':1.2,'stroke-opacity':0.7}));
      }
    }
    // lines
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='line'){
        // extend to SVG edges
        const [ax,ay]=o.p1, [bx,by]=o.p2;
        const dx=bx-ax, dy=by-ay;
        const L = 20;
        svg.appendChild(SVG('line',{x1:tx(ax-L*dx),y1:ty(ay-L*dy),x2:tx(ax+L*dx),y2:ty(ay+L*dy),
          stroke:'#ffd866','stroke-width':1.2,'stroke-opacity':0.7}));
      } else if(o.type==='seg'){
        svg.appendChild(SVG('line',{x1:tx(o.p1[0]),y1:ty(o.p1[1]),x2:tx(o.p2[0]),y2:ty(o.p2[1]),
          stroke:'#e07a5f','stroke-width':2}));
      }
    }
    // points
    for(const [n,o] of Object.entries(objs)){
      if(o.type==='point'){
        svg.appendChild(SVG('circle',{cx:tx(o.pos[0]),cy:ty(o.pos[1]),r:6,
          fill:o.highlight?'#ffd866':'#e8ecf1', stroke:'#111','stroke-width':1.5}));
        const label = SVG('text',{x:tx(o.pos[0])+9,y:ty(o.pos[1])-8,'font-size':13,fill:'#fff','font-weight':600});
        label.textContent = n;
        svg.appendChild(label);
      }
    }

    // readout: current step description
    if(step===0){
      ro.innerHTML = `<i>${con.summary}</i><br><span class="small">click "step ▶" to begin.</span>`;
    } else {
      const st = con.steps[step-1];
      const desc = st.text || describeStep(st);
      ro.innerHTML = `<b>step ${step}</b>: ${desc}`;
      if(step===con.steps.length){
        ro.innerHTML += `<br><span style="color:var(--green)">construction complete — every coordinate lies in a tower of quadratic extensions of ℚ.</span>`;
      }
    }
  }

  function describeStep(st){
    if(st.type==='point') return `place point <b>${st.name}</b>`;
    if(st.type==='circle') return `draw circle centered at ${st.center} through ${st.through} — name it ${st.name}`;
    if(st.type==='line') return `draw line through ${st.p1} and ${st.p2}`;
    if(st.type==='seg') return `connect ${st.p1}-${st.p2} with a segment`;
    if(st.type==='intersect') return `mark intersection ${st.name}`;
    return '';
  }

  function intersect(what, objs, pickK, avoid){
    const os = what.map(n => typeof n==='string'? objs[n] : n);
    if(os.length!==2 || !os[0] || !os[1]) return null;
    let candidates = [];
    const [A,B] = os;
    if(A.axis==='x'){
      // intersection of x-axis with some other object
      return intersect([{type:'line',p1:[-1,0],p2:[1,0]}, B], {}, pickK, avoid);
    }
    if(B.axis==='x'){
      return intersect([A,{type:'line',p1:[-1,0],p2:[1,0]}], {}, pickK, avoid);
    }
    if(A.type==='circle' && B.type==='circle') candidates = ccInt(A,B);
    else if(A.type==='line' && B.type==='circle') candidates = lcInt(A,B);
    else if(A.type==='circle' && B.type==='line') candidates = lcInt(B,A);
    else if(A.type==='line' && B.type==='line') candidates = llInt(A,B);
    // filter avoid
    if(avoid && avoid.length){
      const avoidPts = avoid.map(n=>objs[n]?.pos).filter(Boolean);
      candidates = candidates.filter(p => !avoidPts.some(q => Math.hypot(p[0]-q[0], p[1]-q[1])<1e-6));
    }
    return candidates[pickK % Math.max(candidates.length,1)] || null;
  }
  function ccInt(A,B){
    const [ax,ay]=A.center, [bx,by]=B.center, r1=A.radius, r2=B.radius;
    const d = Math.hypot(bx-ax, by-ay);
    if(d>r1+r2 || d<Math.abs(r1-r2) || d===0) return [];
    const a = (r1*r1 - r2*r2 + d*d)/(2*d);
    const h = Math.sqrt(Math.max(0, r1*r1 - a*a));
    const xm = ax + a*(bx-ax)/d;
    const ym = ay + a*(by-ay)/d;
    const ox = -(by-ay)/d * h;
    const oy = (bx-ax)/d * h;
    return [[xm+ox, ym+oy],[xm-ox, ym-oy]];
  }
  function lcInt(L,C){
    // parameterize line: p1 + t*(p2-p1)
    const [ax,ay]=L.p1, [bx,by]=L.p2; const [cx2,cy2]=C.center; const r = C.radius;
    const dx=bx-ax, dy=by-ay;
    const ex=ax-cx2, ey=ay-cy2;
    const A = dx*dx+dy*dy;
    const B = 2*(ex*dx+ey*dy);
    const Cc = ex*ex+ey*ey - r*r;
    const disc = B*B - 4*A*Cc;
    if(disc<0) return [];
    const t1 = (-B+Math.sqrt(disc))/(2*A), t2 = (-B-Math.sqrt(disc))/(2*A);
    return [[ax+t1*dx, ay+t1*dy],[ax+t2*dx, ay+t2*dy]];
  }
  function llInt(L1,L2){
    const [a,b]=L1.p1, [c,d]=L1.p2, [e,f]=L2.p1, [g,h]=L2.p2;
    const denom = (c-a)*(h-f)-(d-b)*(g-e);
    if(Math.abs(denom)<1e-9) return [];
    const t = ((e-a)*(h-f)-(f-b)*(g-e))/denom;
    return [[a+t*(c-a), b+t*(d-b)]];
  }

  pick.addEventListener('change',()=>{key=pick.value; step=0; redraw()});
  prev.addEventListener('click',()=>{step=Math.max(0,step-1); redraw()});
  next.addEventListener('click',()=>{step=Math.min(CONS[key].steps.length,step+1); redraw()});
  all.addEventListener('click',()=>{step=CONS[key].steps.length; redraw()});
  reset.addEventListener('click',()=>{step=0; redraw()});

  // init
  key='equilateral'; pick.value=key; step=0; redraw();
})();

