const nIn = $('#ng-n'), go = $('#ng-go'), out = $('#ng-out'),
      hint = $('#ng-hint'), svg = $('#ng-svg');
const FERMAT = [3,5,17,257,65537];
function isFermatPrime(p){ return FERMAT.includes(p); }
function check(){
  let n = parseInt(nIn.value,10);
  if(!isFinite(n) || n<3){ out.textContent='n must be ≥ 3'; svg.innerHTML=''; return; }
  if(n>100000){ out.textContent='n too large — pick ≤ 100000'; svg.innerHTML=''; return; }
  const F = factorizeInt(n);
  const fstr = F.map(([p,e])=>e===1?`${p}`:`${p}^${e}`).join(' · ');
  // strip factors of 2
  let twos = 0, oddPrimes = [];
  let bad = false, reasons = [];
  for(const [p,e] of F){
    if(p===2){ twos = e; }
    else {
      if(e>1){ bad = true; reasons.push(`${p} appears with exponent ${e} (must be 1)`); }
      if(!isFermatPrime(p)){ bad = true; reasons.push(`${p} is not a Fermat prime (need one of ${FERMAT.join(', ')})`); }
      oddPrimes.push(p);
    }
  }
  const phi = (function(){
    let r = n;
    for(const [p] of F) r = r - r/p;
    return Math.round(r);
  })();
  const phiFact = factorizeInt(phi);
  const phiIs2 = phiFact.length===0 || (phiFact.length===1 && phiFact[0][0]===2);
  const verdict = !bad && phiIs2;
  let msg = `n = ${n} = ${fstr || '1'}\n`;
  msg += `φ(n) = ${phi} = ${phiFact.map(([p,e])=>e===1?`${p}`:`${p}^${e}`).join(' · ') || '1'}\n`;
  msg += `odd-prime factors of n: ${oddPrimes.length?oddPrimes.join(', '):'none'}\n`;
  if(verdict){
    msg += `\n✓ φ(n) is a power of 2 — the regular ${n}-gon IS constructible.`;
    if(oddPrimes.length===0) msg += `\n    (n is a pure power of 2: bisection from a square.)`;
    else msg += `\n    (odd part = distinct Fermat primes: ${oddPrimes.join(' · ')}.)`;
  } else {
    msg += `\n✗ the regular ${n}-gon is NOT constructible.`;
    for(const r of reasons) msg += `\n    • ${r}`;
    if(phiIs2===false && reasons.length===0){
      msg += `\n    • φ(n) = ${phi} is not a power of 2`;
    }
  }
  out.textContent = msg;
  hint.textContent = verdict?'constructible':'not constructible';
  hint.style.color = verdict?'var(--green)':'var(--pink)';
  drawPoly(n, verdict);
}
function drawPoly(n, ok){
  svg.innerHTML = '';
  const R = 105, col = ok ? 'var(--green)' : 'var(--pink)';
  const circ = SVG('circle',{cx:0,cy:0,r:R,fill:'none',stroke:'var(--line)','stroke-dasharray':'3 3'});
  svg.appendChild(circ);
  if(n>200){
    const t = SVG('text',{x:0,y:5,'text-anchor':'middle',fill:'var(--mute)','font-size':13});
    t.textContent = `${n}-gon (too many sides to draw)`;
    svg.appendChild(t);
    return;
  }
  const pts = [];
  for(let k=0;k<n;k++){
    const a = -Math.PI/2 + 2*Math.PI*k/n;
    pts.push([R*Math.cos(a), R*Math.sin(a)]);
  }
  const poly = SVG('polygon',{
    points: pts.map(p=>p.join(',')).join(' '),
    fill: ok?'rgba(131,193,103,0.08)':'rgba(224,122,95,0.05)',
    stroke: col, 'stroke-width': n>60?1:1.6
  });
  svg.appendChild(poly);
  if(n<=24){
    for(const [x,y] of pts){
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:2.4,fill:col}));
    }
  }
  if(!ok){
    const x1 = SVG('line',{x1:-R*0.9,y1:-R*0.9,x2:R*0.9,y2:R*0.9,stroke:'var(--pink)','stroke-width':3,opacity:0.6});
    const x2 = SVG('line',{x1:-R*0.9,y1:R*0.9,x2:R*0.9,y2:-R*0.9,stroke:'var(--pink)','stroke-width':3,opacity:0.6});
    svg.appendChild(x1); svg.appendChild(x2);
  }
}
go.addEventListener('click',check);
nIn.addEventListener('keydown',e=>{if(e.key==='Enter') check()});
check();

