const TAU = 2*Math.PI;
function pol(r,t){ return [r*Math.cos(t), r*Math.sin(t)]; }
const cbrt2 = Math.cbrt(2), qrt2 = Math.pow(2,0.25);
// ω = e^{2πi/3}, ζ_5, ζ_7, ζ_8, i, etc.
function permId(n){return Array.from({length:n},(_,i)=>i)}
// -- roots of x^5 - x - 1 computed with Durand-Kerner (approx)
function dk(coeffs){
  const n = coeffs.length-1;
  const C = coeffs.map(c=>[c,0]);
  function cmul(a,b){return [a[0]*b[0]-a[1]*b[1], a[0]*b[1]+a[1]*b[0]]}
  function cadd(a,b){return [a[0]+b[0], a[1]+b[1]]}
  function csub(a,b){return [a[0]-b[0], a[1]-b[1]]}
  function cdiv(a,b){const d = b[0]*b[0]+b[1]*b[1]; return [(a[0]*b[0]+a[1]*b[1])/d,(a[1]*b[0]-a[0]*b[1])/d]}
  function eval_(x){let y=[C[n][0],C[n][1]]; for(let i=n-1;i>=0;i--) y=cadd(cmul(y,x),C[i]); return y;}
  let z = []; const r0=0.9, a0=0.4;
  for(let k=0;k<n;k++) z.push([r0*Math.cos(a0+TAU*k/n), r0*Math.sin(a0+TAU*k/n)]);
  for(let it=0;it<80;it++){
    for(let k=0;k<n;k++){
      let prod=[1,0];
      for(let j=0;j<n;j++){ if(j!==k) prod = cmul(prod, csub(z[k],z[j])); }
      z[k] = csub(z[k], cdiv(eval_(z[k]), prod));
    }
  }
  return z;
}

// each preset: roots in C, labels, automorphism list (each a permutation of indices), group description
const PRESETS = {
  'x2-2': (()=>{
    return {
      poly:'x^2-2', rlabels:['√2','-√2'],
      roots: [[Math.sqrt(2),0],[-Math.sqrt(2),0]],
      auts: [{name:'e', perm:[0,1]}, {name:'σ', perm:[1,0]}],
      field:'ℚ(√2)', deg:2, group:'ℤ/2',
      note:'Single quadratic. The only non-trivial automorphism negates √2; ℚ stays fixed. Textbook conjugation.'
    };
  })(),
  'x2+1': (()=>{
    return {
      poly:'x^2+1', rlabels:['i','-i'],
      roots:[[0,1],[0,-1]],
      auts:[{name:'e', perm:[0,1]}, {name:'σ (conj)', perm:[1,0]}],
      field:'ℚ(i)', deg:2, group:'ℤ/2',
      note:'Complex conjugation; Gaussian integers sit inside.'
    };
  })(),
  'x3-2': (()=>{
    const r = cbrt2;
    // roots: r, r·ω, r·ω²
    const ω1 = [Math.cos(TAU/3), Math.sin(TAU/3)];
    const ω2 = [Math.cos(2*TAU/3), Math.sin(2*TAU/3)];
    return {
      poly:'x^3-2', rlabels:['∛2','∛2·ω','∛2·ω²'],
      roots:[[r,0],[r*ω1[0],r*ω1[1]],[r*ω2[0],r*ω2[1]]],
      // S_3 in cycle notation on {0,1,2}
      auts:[
        {name:'e', perm:[0,1,2]},
        {name:'(12)', perm:[1,0,2]},
        {name:'(13)', perm:[2,1,0]},
        {name:'(23)', perm:[0,2,1]},
        {name:'(123)', perm:[1,2,0]},
        {name:'(132)', perm:[2,0,1]},
      ],
      field:'ℚ(∛2, ω)', deg:6, group:'S₃',
      note:'ℚ(∛2) has only one real cube root of 2 — not Galois. Adjoining ω=e^{2πi/3} completes the splitting field. [ℚ(∛2,ω):ℚ] = 3·2 = 6; group is all of S_3.'
    };
  })(),
  'x4-2': (()=>{
    const r = qrt2;
    // roots: r, ir, -r, -ir (i.e. r·ζ_4^k)
    return {
      poly:'x^4-2', rlabels:['⁴√2','i⁴√2','-⁴√2','-i⁴√2'],
      roots:[[r,0],[0,r],[-r,0],[0,-r]],
      // D_4 = ⟨ρ, τ⟩ where ρ is cyclic shift (0→1→2→3→0), τ is complex conjugation (0,2 fixed; 1↔3)
      // 8 elements: e, ρ, ρ², ρ³, τ, ρτ, ρ²τ, ρ³τ
      auts: (()=>{
        const ρ = [1,2,3,0];
        const τ = [0,3,2,1];
        function compose(a,b){return a.map((_,i)=>a[b[i]])}
        const es=[{name:'e',perm:[0,1,2,3]}];
        let cur=[0,1,2,3];
        for(let k=1;k<4;k++){ cur = compose(ρ,cur); es.push({name:`ρ${'²³⁴'[k-1]||''}`, perm:cur}); }
        es.push({name:'τ', perm:τ});
        es.push({name:'ρτ', perm:compose(ρ,τ)});
        es.push({name:'ρ²τ', perm:compose(ρ,compose(ρ,τ))});
        es.push({name:'ρ³τ', perm:compose(ρ,compose(ρ,compose(ρ,τ)))});
        // fix names: ρ² etc
        es[1].name='ρ'; es[2].name='ρ²'; es[3].name='ρ³';
        return es;
      })(),
      field:'ℚ(⁴√2, i)', deg:8, group:'D₄ (order 8)',
      note:'Two generators: ρ = multiply-by-i (rotates roots 90°), τ = complex conjugation. They satisfy ρ⁴=τ²=e and τρτ=ρ⁻¹. That is the dihedral group D₄.'
    };
  })(),
  'x4+1': (()=>{
    // roots = ζ_8^{1,3,5,7}
    const z = k => [Math.cos(k*TAU/8), Math.sin(k*TAU/8)];
    return {
      poly:'x^4+1', rlabels:['ζ','ζ³','ζ⁵','ζ⁷'],
      roots:[z(1),z(3),z(5),z(7)],
      // Gal(Q(ζ_8)/Q) = (Z/8)^× = {1,3,5,7}, which is Z/2 × Z/2
      // σ_a : ζ → ζ^a ; acts on indices (1,3,5,7) by multiplication mod 8
      auts: (()=>{
        const units = [1,3,5,7];
        return units.map(a=>({
          name: a===1?'e':`σ${['','₁','','₃','','₅','','₇'][a]}`,
          perm: units.map(u=>units.indexOf((u*a)%8))
        }));
      })(),
      field:'ℚ(ζ₈)', deg:4, group:'(ℤ/8)× ≅ ℤ/2 × ℤ/2',
      note:'All roots are powers of a single root of unity ζ = ζ_8. An automorphism is determined by ζ↦ζ^a for a coprime to 8, so Gal = (ℤ/8)×. This has order 4 but is not cyclic — {1,3,5,7} under × mod 8 is the Klein four-group.'
    };
  })(),
  'cyc5': (()=>{
    const z = k => [Math.cos(k*TAU/5), Math.sin(k*TAU/5)];
    return {
      poly:'Φ_5(x)', rlabels:['ζ','ζ²','ζ³','ζ⁴'],
      roots:[z(1),z(2),z(3),z(4)],
      // Gal(Q(ζ_5)/Q) = (Z/5)^× = cyclic of order 4, generator 2: 2^k mod 5 = 2,4,3,1
      auts: (()=>{
        const units = [1,2,3,4];
        return units.map(a=>({
          name: a===1?'e':`σ→${a}`,
          perm: units.map(u=>units.indexOf((u*a)%5))
        }));
      })(),
      field:'ℚ(ζ₅)', deg:4, group:'(ℤ/5)× ≅ ℤ/4',
      note:'Cyclic of order 4: generator σ: ζ↦ζ². The unique index-2 subgroup gives the subfield ℚ(√5), since ζ+ζ⁴ = 2cos(2π/5) = (√5−1)/2.'
    };
  })(),
  'cyc7': (()=>{
    const z = k => [Math.cos(k*TAU/7), Math.sin(k*TAU/7)];
    return {
      poly:'Φ_7(x)', rlabels:['ζ','ζ²','ζ³','ζ⁴','ζ⁵','ζ⁶'],
      roots:[z(1),z(2),z(3),z(4),z(5),z(6)],
      auts: (()=>{
        const units = [1,2,3,4,5,6];
        return units.map(a=>({
          name: a===1?'e':`ζ↦ζ${['','¹','²','³','⁴','⁵','⁶'][a]}`,
          perm: units.map(u=>units.indexOf((u*a)%7))
        }));
      })(),
      field:'ℚ(ζ₇)', deg:6, group:'(ℤ/7)× ≅ ℤ/6',
      note:'Cyclic of order 6, generator 3 (3^k mod 7 = 3,2,6,4,5,1). Its subgroup of order 3 gives ℚ(√−7), the unique quadratic subfield.'
    };
  })(),
  'x5-x-1': (()=>{
    // coefficients low-to-high: -1, -1, 0, 0, 0, 1
    const rs = dk([-1,-1,0,0,0,1]);
    // normalize: sort roots by angle then abs to get deterministic labelling — not needed, use as-is
    return {
      poly:'x^5-x-1', rlabels:['r₁','r₂','r₃','r₄','r₅'],
      roots: rs,
      // Can't enumerate all 120 of S_5 as buttons; show identity and a handful of generators
      auts: [
        {name:'e', perm:[0,1,2,3,4]},
        {name:'(12)', perm:[1,0,2,3,4]},
        {name:'(12345)', perm:[1,2,3,4,0]},
        {name:'(12)(34)', perm:[1,0,3,2,4]},
        {name:'(123)', perm:[1,2,0,3,4]},
        {name:'(13524)', perm:[2,3,4,0,1]},
      ],
      field:'splitting field of x^5−x−1', deg:120, group:'S₅ (order 120)',
      note:'Irreducible over ℚ with discriminant non-square and transitive on 5 points including a transposition ⇒ Galois group is all of S_5. This is the exhibit in §6: because S_5 is not solvable, x^5−x−1 has no solution in radicals.'
    };
  })(),
};

