function compose(a,b){ return a.map((_,i)=>a[b[i]]); }
function inv(p){ const q=Array(p.length); p.forEach((v,i)=>{q[v]=i}); return q; }
function pkey(p){ return p.join(','); }
function perms(n){
  if(n===0) return [[]];
  const out=[], sub=perms(n-1);
  for(const p of sub) for(let i=0;i<=n-1;i++){
    const q=p.slice(); q.splice(i,0,n-1); out.push(q);
  }
  return out;
}
function parity(p){
  let s=0; const seen=Array(p.length).fill(false);
  for(let i=0;i<p.length;i++){
    if(seen[i]) continue;
    let j=i, L=0;
    while(!seen[j]){ seen[j]=true; j=p[j]; L++; }
    s += L-1;
  }
  return s%2===0 ? 1 : -1;
}
function closureOf(gens, n){
  const id = Array.from({length:n},(_,i)=>i);
  const s = new Map();
  s.set(pkey(id), id);
  for(const g of gens) s.set(pkey(g), g);
  let changed = true;
  while(changed){
    changed = false;
    const arr = [...s.values()];
    for(const a of arr){
      for(const b of arr){
        const c = compose(a,b);
        const k = pkey(c);
        if(!s.has(k)){ s.set(k,c); changed=true; }
      }
    }
  }
  return [...s.values()];
}
function derived(G, n){
  const comms = [];
  for(const a of G){
    for(const b of G){
      comms.push(compose(compose(a,b), compose(inv(a),inv(b))));
    }
  }
  return closureOf(comms, n);
}
function cyclic(n){
  // Z/n via rotation on n points
  const r = Array.from({length:n},(_,i)=>(i+1)%n);
  const els = [Array.from({length:n},(_,i)=>i)];
  let cur = els[0];
  for(let k=1;k<n;k++){ cur = compose(r, cur); els.push(cur); }
  return {els, n};
}
function dihedral(n){
  const r = Array.from({length:n},(_,i)=>(i+1)%n);
  const s = Array.from({length:n},(_,i)=>(n-i)%n);
  const gens = [r, s];
  return {els: closureOf(gens, n), n};
}
function klein(){
  // V_4 on 4 points: {e, (12)(34), (13)(24), (14)(23)}
  return {els:[[0,1,2,3],[1,0,3,2],[2,3,0,1],[3,2,1,0]], n:4};
}
function sym(n){ return {els: perms(n), n}; }
function alt(n){ return {els: perms(n).filter(p=>parity(p)===1), n}; }

const BUILDERS = {
  'Z5': cyclic(5),
  'V4': klein(),
  'D4': dihedral(4),
  'S3': sym(3),
  'A4': alt(4),
  'S4': sym(4),
  'D5': dihedral(5),
  'A5': alt(5),
  'S5': sym(5),
};
const LABELS = {'Z5':'ℤ/5','V4':'V₄','D4':'D₄','S3':'S₃','A4':'A₄','S4':'S₄','D5':'D₅','A5':'A₅','S5':'S₅'};

// Try to name a subgroup by its order + a coarse signature (abelian?, contains 3-cycle?)
function nameByOrder(els, order, n){
  if(order===1) return '{e}';
  // check abelian
  let abelian = true;
  outer: for(const a of els){
    for(const b of els){
      const ab = compose(a,b), ba = compose(b,a);
      for(let i=0;i<n;i++) if(ab[i]!==ba[i]){ abelian=false; break outer; }
    }
  }
  const map = {
    '2': abelian? 'ℤ/2' : 'S₂',
    '3': 'ℤ/3',
    '4': abelian ? 'ℤ/4 or V₄' : 'ℤ/4 or V₄',
    '5': 'ℤ/5',
    '6': abelian ? 'ℤ/6' : 'S₃',
    '8': abelian ? 'ℤ/2×ℤ/4 etc.' : 'D₄',
    '10': 'D₅',
    '12': abelian ? 'ℤ/12' : 'A₄',
    '24': 'S₄',
    '60': 'A₅',
    '120': 'S₅',
  };
  return map[String(order)] || `order ${order}`;
}

const pick = $('#sv-pick'), svg = $('#sv-svg'), out = $('#sv-out');

function render(){
  const key = pick.value;
  const G = BUILDERS[key];
  const n = G.n;
  const series = [G.els];
  while(true){
    const d = derived(series[series.length-1], n);
    if(d.length === series[series.length-1].length){
      series.push(d); break;
    }
    series.push(d);
    if(d.length===1) break;
    if(series.length>8) break;
  }
  const orders = series.map(s=>s.length);
  const solvable = orders[orders.length-1]===1;

  // draw
  svg.innerHTML = '';
  const W=620, H=220, pad=40;
  const xs = orders.map((_,i)=> pad + i*(W-2*pad)/Math.max(orders.length-1,1));
  const maxO = Math.max(...orders);
  function y(o){ // log scale
    const v = Math.log(o)/Math.log(Math.max(maxO,2));
    return H-pad - v*(H-2*pad-20);
  }
  // baseline
  svg.appendChild(SVG('line',{x1:pad-10,y1:H-pad,x2:W-pad+10,y2:H-pad,stroke:'var(--line)'}));
  // vertical axis ticks
  for(const val of [1,2,5,12,60,120]){
    if(val>maxO) continue;
    const yy = y(val);
    svg.appendChild(SVG('line',{x1:pad-15,y1:yy,x2:pad-5,y2:yy,stroke:'var(--line)'}));
    const tt = SVG('text',{x:pad-20,y:yy+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    tt.textContent = String(val);
    svg.appendChild(tt);
  }
  // connecting path
  let d = '';
  xs.forEach((xx,i)=>{ d += (i===0?'M':'L') + xx + ' ' + y(orders[i]); });
  svg.appendChild(SVG('path',{d,fill:'none',stroke: solvable?'var(--green)':'var(--pink)','stroke-width':2}));
  // dots + labels
  orders.forEach((o,i)=>{
    const xx = xs[i], yy = y(o);
    svg.appendChild(SVG('circle',{cx:xx,cy:yy,r:5,fill:solvable?'var(--green)':'var(--pink)'}));
    const lab = i===0? LABELS[key] : (`G${"⁽⁾".replace('⁽','')}`);
    const supers = ['','′','″','‴','⁽⁴⁾','⁽⁵⁾','⁽⁶⁾','⁽⁷⁾'];
    const tag = i===0 ? LABELS[key] : (`G${supers[i]||'⁽'+i+'⁾'}`);
    const t1 = SVG('text',{x:xx,y:yy-14,'text-anchor':'middle','font-size':12,fill:'#e8ecf1'});
    t1.textContent = tag;
    svg.appendChild(t1);
    const t2 = SVG('text',{x:xx,y:H-pad+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t2.textContent = `|·| = ${o}`;
    svg.appendChild(t2);
  });

  // annotated series
  const parts = series.map((s,i)=>{
    const tag = i===0 ? LABELS[key] : `G${['','′','″','‴','⁽⁴⁾'][i]||'⁽'+i+'⁾'}`;
    return `${tag}  (order ${s.length}, ≈ ${nameByOrder(s,s.length,n)})`;
  });
  let msg = parts.join('\n  ▽ [·,·]\n');
  msg += '\n\n';
  if(solvable) msg += `✓ chain terminates at {e} — ${LABELS[key]} is SOLVABLE`;
  else msg += `✗ chain stabilizes at order ${orders[orders.length-1]} ≠ 1 — ${LABELS[key]} is NOT solvable`;
  out.textContent = msg;
}
pick.addEventListener('change',render);
render();

