const CLASSES = [
  {name:'{e}',  rep:'e',          ctype:'1⁵',    size:1},
  {name:'double transpositions', rep:'(12)(34)', ctype:'2²·1', size:15},
  {name:'3-cycles', rep:'(123)',  ctype:'3·1²',  size:20},
  {name:'5-cycles (class A)', rep:'(12345)',  ctype:'5',     size:12},
  {name:'5-cycles (class B)', rep:'(13524)',  ctype:'5',     size:12},
];
const tbody = $('#a5-rows'), out = $('#a5-out');
const on = Array(CLASSES.length).fill(false);
on[0] = true; // identity class always included to make it meaningful
function update(){
  let sum = 0, parts = [];
  CLASSES.forEach((c,i)=>{
    if(on[i]){ sum += c.size; parts.push(c.size); }
  });
  const hasE = on[0];
  const isSub = (60 % sum) === 0;
  const isEverything = sum===60;
  const isTrivial = sum===1;
  let verdict;
  if(!hasE){
    verdict = 'must include the identity class to be a subgroup';
  } else if(!isSub){
    verdict = `sum = ${sum} does not divide 60 — cannot be a subgroup order (Lagrange)`;
  } else if(isTrivial || isEverything){
    verdict = `sum = ${sum} — ${isTrivial?'trivial subgroup {e}':'all of A₅'} ✓`;
  } else {
    verdict = `sum = ${sum} divides 60, but check further…`;
  }
  out.textContent =
    `selected: ${parts.length?parts.join(' + ') + ' = ' + sum : '0'}\n` +
    `${verdict}`;
  out.style.color = (!hasE || !isSub) ? 'var(--pink)' :
                    (isTrivial||isEverything) ? 'var(--green)' : 'var(--yellow)';
}
CLASSES.forEach((c,i)=>{
  const tr = document.createElement('tr');
  tr.innerHTML = `
    <td style="padding:.35rem .5rem"><input type="checkbox" ${on[i]?'checked':''} data-i="${i}"></td>
    <td style="padding:.35rem .5rem">${c.name}</td>
    <td style="padding:.35rem .5rem;font-family:ui-monospace,monospace">${c.rep}</td>
    <td style="padding:.35rem .5rem">${c.ctype}</td>
    <td style="padding:.35rem .5rem;color:var(--yellow);text-align:right">${c.size}</td>
  `;
  tbody.appendChild(tr);
});
tbody.addEventListener('change',e=>{
  const i = parseInt(e.target.dataset.i,10);
  on[i] = e.target.checked; update();
});
update();

